import React, { useState, useEffect } from 'react';
import UploadZone from '../components/UploadZone';
import SkillSelector from '../components/SkillSelector';
import CandidateCard from '../components/CandidateCard';
import StatsBar from '../components/StatsBar';
import { uploadResumes, matchCandidates, parseJD, healthCheck, getSampleCandidates } from '../utils/api';

// ─── Shared Styles ────────────────────────────────────────────
const s = {
  page: { minHeight: '100vh', background: '#f3f4f6' },
  layout: { display: 'grid', gridTemplateColumns: '380px 1fr', gap: 24, maxWidth: 1280, margin: '0 auto', padding: '24px 24px 60px' },
  // Left Panel
  panel: { background: '#fff', border: '1px solid #e5e7eb', borderRadius: 10, overflow: 'hidden', position: 'sticky', top: 80, boxShadow: '0 1px 3px rgba(0,0,0,0.07)' },
  panelHead: { padding: '14px 20px', borderBottom: '1px solid #f3f4f6', display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: '#f9fafb' },
  panelTitle: { fontWeight: 600, fontSize: 14, color: '#111827' },
  panelBody: { padding: 20 },
  sectionLabel: { fontSize: 11, fontWeight: 600, color: '#6b7280', textTransform: 'uppercase', letterSpacing: '0.07em', marginBottom: 8, marginTop: 18, display: 'block' },
  textarea: {
    width: '100%', padding: '10px 12px', border: '1px solid #d1d5db', borderRadius: 6,
    fontSize: 13, fontFamily: 'Inter, sans-serif', resize: 'vertical', minHeight: 80,
    color: '#111827', background: '#fff', lineHeight: 1.6,
    outline: 'none',
  },
  input: {
    width: '100%', padding: '9px 12px', border: '1px solid #d1d5db', borderRadius: 6,
    fontSize: 13, fontFamily: 'Inter, sans-serif', color: '#111827', outline: 'none',
  },
  analyzeBtn: (loading) => ({
    width: '100%', marginTop: 20, padding: '12px',
    background: loading ? '#93c5fd' : '#2563eb',
    color: '#fff', border: 'none', borderRadius: 8,
    fontSize: 14, fontWeight: 600, cursor: loading ? 'wait' : 'pointer',
    transition: 'background 0.2s',
  }),
  jdBtn: {
    padding: '8px 14px', background: '#f3f4f6', color: '#374151',
    border: '1px solid #d1d5db', borderRadius: 6, fontSize: 12, fontWeight: 500, cursor: 'pointer',
  },
  // Right Panel
  rightPanel: {},
  stepBar: { display: 'flex', marginBottom: 20, background: '#fff', border: '1px solid #e5e7eb', borderRadius: 8, overflow: 'hidden' },
  step: (active, done) => ({
    flex: 1, padding: '10px 8px', textAlign: 'center', fontSize: 12, fontWeight: 500,
    borderBottom: `2px solid ${done ? '#16a34a' : active ? '#2563eb' : 'transparent'}`,
    color: done ? '#16a34a' : active ? '#2563eb' : '#9ca3af',
    background: done ? '#f0fdf4' : active ? '#eff6ff' : 'transparent',
  }),
  filterBar: { display: 'flex', gap: 8, marginBottom: 16, flexWrap: 'wrap', alignItems: 'center' },
  filterChip: (active) => ({
    padding: '6px 14px', borderRadius: 20, fontSize: 12, fontWeight: 500, cursor: 'pointer',
    border: `1px solid ${active ? '#2563eb' : '#d1d5db'}`,
    background: active ? '#2563eb' : '#fff',
    color: active ? '#fff' : '#374151',
  }),
  searchInput: {
    flex: 1, maxWidth: 220, padding: '7px 12px', border: '1px solid #d1d5db',
    borderRadius: 20, fontSize: 12, outline: 'none', fontFamily: 'Inter, sans-serif',
  },
  emptyState: {
    background: '#fff', border: '1px dashed #d1d5db', borderRadius: 10,
    padding: '60px 20px', textAlign: 'center',
  },
  emptyIcon: { fontSize: 48, marginBottom: 16, opacity: 0.4 },
  emptyTitle: { fontWeight: 600, fontSize: 18, color: '#6b7280', marginBottom: 8 },
  emptyDesc: { fontSize: 13, color: '#9ca3af', lineHeight: 1.7 },
  errorBox: {
    background: '#fef2f2', border: '1px solid #fecaca', borderRadius: 8,
    padding: '12px 16px', marginBottom: 16, fontSize: 13, color: '#991b1b',
  },
  successBox: {
    background: '#f0fdf4', border: '1px solid #bbf7d0', borderRadius: 8,
    padding: '12px 16px', marginBottom: 16, fontSize: 13, color: '#166534',
  },
  toast: (show) => ({
    position: 'fixed', bottom: 24, right: 24, zIndex: 200,
    background: '#1f2937', color: '#fff', padding: '12px 20px', borderRadius: 8,
    fontSize: 13, fontWeight: 500, boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
    transform: show ? 'translateY(0)' : 'translateY(80px)',
    opacity: show ? 1 : 0, transition: 'all 0.3s',
  }),
  divider: { borderBottom: '1px solid #f3f4f6', margin: '16px 0' },
};

// ─── Step Indicator ───────────────────────────────────────────
function StepBar({ currentStep }) {
  const steps = ['1. Upload Resumes', '2. Set Job Requirements', '3. Analyze', '4. Review Results'];
  return (
    <div style={s.stepBar}>
      {steps.map((label, i) => (
        <div key={label} style={s.step(i + 1 === currentStep, i + 1 < currentStep)}>{label}</div>
      ))}
    </div>
  );
}

export default function RecruiterDashboard() {
  const [files, setFiles] = useState([]);
  const [jobTitle, setJobTitle] = useState('');
  const [jobDescription, setJobDescription] = useState('');
  const [requiredSkills, setRequiredSkills] = useState([]);
  const [minExp, setMinExp] = useState('');
  const [candidates, setCandidates] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [filterMode, setFilterMode] = useState('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [apiOnline, setApiOnline] = useState(false);
  const [toast, setToast] = useState({ show: false, msg: '' });
  const [parsedFromJD, setParsedFromJD] = useState(false);

  // Health check
  useEffect(() => {
    healthCheck()
      .then(() => setApiOnline(true))
      .catch(() => setApiOnline(false));
  }, []);

  // Step tracker
  useEffect(() => {
    if (files.length > 0 && step < 2) setStep(2);
  }, [files]);

  useEffect(() => {
    if ((jobDescription || requiredSkills.length > 0) && step < 3) setStep(Math.max(step, 2));
  }, [jobDescription, requiredSkills]);

  // Filter candidates
  useEffect(() => {
    let result = [...candidates];
    if (filterMode === 'high') result = result.filter(c => c.final_score >= 70);
    else if (filterMode === 'med') result = result.filter(c => c.final_score >= 40 && c.final_score < 70);
    else if (filterMode === 'low') result = result.filter(c => c.final_score < 40);
    if (searchQuery) result = result.filter(c => c.name?.toLowerCase().includes(searchQuery.toLowerCase()));
    setFiltered(result);
  }, [candidates, filterMode, searchQuery]);

  const showToast = (msg) => {
    setToast({ show: true, msg });
    setTimeout(() => setToast({ show: false, msg: '' }), 3000);
  };

  const handleParseJD = async () => {
    if (!jobDescription.trim()) return;
    try {
      const res = await parseJD(jobDescription);
      const skills = res.data.extracted_skills || [];
      setRequiredSkills(prev => [...new Set([...prev, ...skills])]);
      setParsedFromJD(true);
      showToast(`Extracted ${skills.length} skills from job description`);
    } catch {
      showToast('Could not parse JD — check API connection');
    }
  };

  const handleLoadSamples = async () => {
    try {
      setLoading(true);
      const res = await getSampleCandidates();
      const samples = res.data.candidates || [];
      setCandidates(samples);
      setStep(4);
      showToast(`✓ Demo loaded`);
    } catch (err) {
      setError('Error loading samples: ' + (err.message || 'Unknown error'));
    } finally {
      setLoading(false);
    }
  };

  const handleAnalyze = async () => {
    if (files.length === 0) { setError('Please upload at least one resume.'); return; }
    if (requiredSkills.length === 0) { setError('Please select at least one required skill.'); return; }
    setError('');
    setSuccess('');
    setLoading(true);
    setStep(3);

    try {
      // 1. Upload & parse resumes
      const uploadRes = await uploadResumes(files);
      const parsed = uploadRes.data.candidates;

      // Validate we got the expected candidates back
      if (!parsed || parsed.length === 0) {
        throw new Error('No candidates returned from upload. Files may not have been processed.');
      }

      // Check if we got errors for all files
      const erroredItems = parsed.filter(p => p.error);
      if (erroredItems.length === parsed.length) {
        throw new Error(`All files failed to process: ${erroredItems.map(e => e.error).join(', ')}`);
      }

      // 2. Match against job requirements
      const matchRes = await matchCandidates(parsed, requiredSkills, jobDescription, minExp);
      const ranked = matchRes.data.ranked_candidates;

      setCandidates(ranked);
      setStep(4);
      const successMsg = `Analysis complete — ${ranked.length} candidates ranked successfully.${erroredItems.length > 0 ? ` (${erroredItems.length} files skipped due to errors)` : ''}`;
      setSuccess(successMsg);
      showToast(`✓ ${ranked.length} candidates ranked`);
    } catch (err) {
      const errorMsg = err.response?.data?.error || err.response?.data?.hint || err.message;
      setError('Error: ' + errorMsg);
      setStep(2);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={s.page}>
      <div style={s.layout}>
        {/* ── LEFT PANEL ── */}
        <div>
          <div style={s.panel}>
            <div style={s.panelHead}>
              <span style={s.panelTitle}>Job Configuration</span>
              <span style={{ fontSize: 11, background: '#f5f2ec', color: '#e8440a', padding: '3px 8px', borderRadius: 4, fontWeight: 500 }}>Recruiter</span>
            </div>
            <div style={s.panelBody}>

              {/* Upload */}
              <span style={{ ...s.sectionLabel, marginTop: 0 }}>📄 Resume Upload</span>
              <UploadZone files={files} setFiles={setFiles} />
              
              <div style={{ display: 'flex', gap: 8, marginTop: 12 }}>
                <button 
                  style={{
                    flex: 1, padding: '8px 12px', background: '#f3f4f6', color: '#374151',
                    border: '1px solid #d1d5db', borderRadius: 6, fontSize: 12, fontWeight: 500, 
                    cursor: 'pointer', whiteSpace: 'nowrap'
                  }}
                  onClick={handleLoadSamples}
                  disabled={loading}
                  title="Load sample resumes to test the app"
                >
                  📋 Try Demo
                </button>
              </div>

              <div style={s.divider} />

              {/* Job Info */}
              <span style={s.sectionLabel}>💼 Job Title</span>
              <input
                style={s.input}
                placeholder="e.g. Senior Data Scientist"
                value={jobTitle}
                onChange={e => setJobTitle(e.target.value)}
              />

              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 16, marginBottom: 8 }}>
                <span style={{ ...s.sectionLabel, marginTop: 0, marginBottom: 0 }}>📋 Job Description</span>
                <button style={s.jdBtn} onClick={handleParseJD}>Auto-extract Skills</button>
              </div>
              <textarea
                style={s.textarea}
                placeholder="Paste the full job description here. Click 'Auto-extract Skills' to detect required skills automatically..."
                value={jobDescription}
                onChange={e => setJobDescription(e.target.value)}
                rows={4}
              />
              {parsedFromJD && (
                <div style={{ fontSize: 11, color: '#16a34a', marginTop: 4 }}>✓ Skills auto-extracted from JD</div>
              )}

              <div style={s.divider} />

              {/* Skills */}
              <span style={s.sectionLabel}>🎯 Required Skills</span>
              <SkillSelector selected={requiredSkills} setSelected={setRequiredSkills} />

              <div style={s.divider} />

              {/* Experience */}
              <span style={s.sectionLabel}>⏱ Minimum Experience</span>
              <input
                style={s.input}
                placeholder="e.g. 3"
                type="number"
                min="0"
                value={minExp}
                onChange={e => setMinExp(e.target.value)}
              />
              <div style={{ fontSize: 11, color: '#9ca3af', marginTop: 4 }}>Years of experience required</div>

              {/* Analyze Button */}
              <button style={s.analyzeBtn(loading)} onClick={handleAnalyze} disabled={loading}>
                {loading ? '⏳ Analyzing Resumes...' : '🔍 Analyze & Rank Candidates'}
              </button>
            </div>
          </div>
        </div>

        {/* ── RIGHT PANEL ── */}
        <div style={s.rightPanel}>
          <StepBar currentStep={step} />

          {error && <div style={s.errorBox}>❌ {error}</div>}
          {success && <div style={s.successBox}>✅ {success}</div>}

          {candidates.length > 0 && (
            <>
              <StatsBar candidates={candidates} />

              {/* Filter Bar */}
              <div style={s.filterBar}>
                <input
                  style={s.searchInput}
                  placeholder="🔍 Search by name..."
                  value={searchQuery}
                  onChange={e => setSearchQuery(e.target.value)}
                />
                {[
                  { key: 'all', label: 'All Candidates' },
                  { key: 'high', label: '🟢 High ≥70%' },
                  { key: 'med', label: '🟡 Medium 40–69%' },
                  { key: 'low', label: '🔴 Low <40%' },
                ].map(f => (
                  <button key={f.key} style={s.filterChip(filterMode === f.key)} onClick={() => setFilterMode(f.key)}>
                    {f.label}
                  </button>
                ))}
                <span style={{ fontSize: 12, color: '#9ca3af', marginLeft: 'auto' }}>
                  {filtered.length} of {candidates.length} shown
                </span>
              </div>

              {/* Cards */}
              {filtered.map((c, i) => (
                <CandidateCard
                  key={c.filename + i}
                  candidate={c}
                  index={i}
                  onShortlist={() => showToast(`${c.name} added to shortlist`)}
                />
              ))}

              {filtered.length === 0 && (
                <div style={{ ...s.emptyState, padding: 30 }}>
                  <div style={{ fontSize: 13, color: '#9ca3af' }}>No candidates match the current filter.</div>
                </div>
              )}
            </>
          )}

          {/* Empty State */}
          {candidates.length === 0 && !loading && (
            <div style={s.emptyState}>
              <div style={s.emptyIcon}>📊</div>
              <div style={s.emptyTitle}>No Results Yet</div>
              <div style={s.emptyDesc}>
                Upload candidate resumes on the left panel,<br />
                configure job requirements, and click<br />
                <strong>"Analyze & Rank Candidates"</strong> to begin.
              </div>
            </div>
          )}

          {/* Loading State */}
          {loading && (
            <div style={{ ...s.emptyState, padding: 50 }}>
              <div style={{ fontSize: 13, color: '#e8440a', fontWeight: 500 }}>
                ⏳ Processing resumes with AI... This may take a few seconds.
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Toast */}
      <div style={s.toast(toast.show)}>{toast.msg}</div>
    </div>
  );
}
